import sys

def calculate_prefix_sum(dna):
    prefix_sum = [[0, 0, 0, 0] for _ in range(len(dna) + 1)]
    mapping = {'A': 0, 'T': 1, 'G': 2, 'C': 3}
    for i in range(len(dna)):
        for j in range(4):
            prefix_sum[i + 1][j] = prefix_sum[i][j]
        prefix_sum[i + 1][mapping[dna[i]]] += 1
    return prefix_sum

def get_section_counts(prefix_sum, start, end):
    counts = [0, 0, 0, 0]
    for i in range(4):
        counts[i] = prefix_sum[end][i] - prefix_sum[start - 1][i]
    return counts

def get_sorted_nucleotides(counts):
    mapping = {0: 'A', 1: 'T', 2: 'G', 3: 'C'}
    sorted_nucleotides = sorted(range(4), key=lambda x: (-counts[x], x))
    return ''.join(mapping[i] for i in sorted_nucleotides)

def main():
    dna = sys.stdin.readline().strip()
    prefix_sum = calculate_prefix_sum(dna)
    num_sections = int(sys.stdin.readline().strip())
    for _ in range(num_sections):
        start, end = map(int, sys.stdin.readline().strip().split())
        counts = get_section_counts(prefix_sum, start, end)
        print(get_sorted_nucleotides(counts))

