    prefix_sum = {'A': [0], 'T': [0], 'G': [0], 'C': [0]}
    for nucleotide in dna:
        for key in prefix_sum:
            prefix_sum[key].append(prefix_sum[key][-1] + (1 if nucleotide == key else 0))
    return prefix_sum

def get_section_counts(prefix_sum, start, end):
    section_counts = {}
    for nucleotide in prefix_sum:
        section_counts[nucleotide] = prefix_sum[nucleotide][end] - prefix_sum[nucleotide][start - 1]
    return section_counts

def get_sorted_nucleotides(section_counts):
    return sorted(section_counts, key=lambda x: (-section_counts[x], x))

