    dna = stdin.readline().strip()
    prefix_sum = calculate_prefix_sum(dna)
    num_sections = int(stdin.readline().strip())
    for _ in range(num_sections):
        start, end = map(int, stdin.readline().strip().split())
        section_counts = get_section_counts(prefix_sum, start, end)
        sorted_nucleotides = get_sorted_nucleotides(section_counts)
        print(''.join(sorted_nucleotides))

