    prev_digit = s[0]
    for i in range(1, len(s)):
        if s[i] == prev_digit:
            count += 1
        else:
            result += str(count) + prev_digit
            count = 1
            prev_digit = s[i]
    result += str(count) + prev_digit
    return result

