import sys
import heapq

def dijkstra(graph, start):
    distances = {node: float('infinity') for node in graph}
    distances[start] = 0
    queue = [(0, start)]
    count = {node: 0 for node in graph}
    count[start] = 1

    while queue:
        current_distance, current_node = heapq.heappop(queue)

        if current_distance > distances[current_node]:
            continue

        for neighbor, weight in graph[current_node].items():
            distance = current_distance + weight

            if distance < distances[neighbor]:
                distances[neighbor] = distance
                count[neighbor] = count[current_node]
                heapq.heappush(queue, (distance, neighbor))
            elif distance == distances[neighbor]:
                count[neighbor] += count[current_node]

    return distances, count

def main():
    n, m, a, b = map(int, sys.stdin.readline().split())
    graph = {i: {} for i in range(1, n + 1)}

    for _ in range(m):
        i1, i2, length = map(int, sys.stdin.readline().split())
        graph[i1][i2] = length
        graph[i2][i1] = length

    distances_from_a, count_from_a = dijkstra(graph, a)
    distances_from_b, count_from_b = dijkstra(graph, b)

    min_distance = distances_from_a[b]

    total_length = sum(sum(graph[node].values()) for node in graph) // 2
    used_length = 0

    for node in graph:
        for neighbor, weight in graph[node].items():
            if distances_from_a[node] + weight + distances_from_b[neighbor] == min_distance and count_from_a[node] * count_from_b[neighbor] > 0:
                used_length += weight

    print(total_length - used_length // 2)

if __name__ == "__main__":
