def cost(x, points):
    total_cost = 0
    for p in points:
        left, right = 0, len(x) - 1
        while right - left > 1:
            mid = (left + right) // 2
            if x[mid] <= p:
                left = mid
            else:
                right = mid
        if left == len(x) - 1:
            total_cost += (x[left] - p) ** 2
        elif right == 0:
            total_cost += (x[right] - p) ** 2
        else:
            d1 = x[left] - p
            d2 = x[right] - p
            if d1 ** 2 < d2 ** 2:
                total_cost += d1 ** 2
            else:
                total_cost += d2 ** 2
    return total_cost

def main():
