    points = [(combined[i * len(combined) // k] + combined[(i + 1) * len(combined) // k - 1]) / 2 for i in range(k)]
    min_cost = cost(x1, points) + cost(x2, points) + len(x1 + x2) * (s / 2) ** 2
    print(min_cost)

