        nearest_access_point = access_points[left]
        while left <= right:
            mid = (left + right) // 2
            if abs(x[i] - access_points[mid]) < abs(x[i] - nearest_access_point):
                nearest_access_point = access_points[mid]
            if x[i] < access_points[mid]:
                right = mid - 1
            else:
                left = mid + 1
        cost += (x[i] - nearest_access_point) ** 2
    return cost

