import sys

def read_input():
    m, n, k, s = map(int, sys.stdin.readline().strip().split())
    x = sorted(list(map(float, sys.stdin.readline().strip().split())) + 
               list(map(lambda x: float(x) + 1j * s, sys.stdin.readline().strip().split())))
    return m + n, k, x

def calculate_cost(x, i, j):
    centroid = (x[i:j].sum() / (j - i)).real
    return sum((x[k].real - centroid) ** 2 + x[k].imag ** 2 for k in range(i, j))

def dynamic_programming(N, k, x):
    cost = [[0.0] * (N + 1) for _ in range(k + 1)]
    for i in range(N + 1):
        cost[1][i] = calculate_cost(x, 0, i)
    for j in range(2, k + 1):
        prev_cost = cost[j - 1]
        curr_cost = cost[j]
        for i in range(j, N + 1):
            curr_cost[i] = min(prev_cost[q] + calculate_cost(x, q, i) for q in range(j - 1, i))
    return cost[k][N]

def main():
    N, k, x = read_input()
    result = dynamic_programming(N, k, x)
    print(f'{result:.10f}')

if __name__ == '__main__':
    main()
